// Generated by OrchestKit Claude Plugin
// Created: 2026-03-05

/**
 * InstructionsLoaded Dispatcher — CC 2.1.69
 *
 * Fires after Claude Code loads instruction files (CLAUDE.md, .claude/rules/*.md, plugin instructions).
 * Runs 3 handlers sequentially, merges their additionalContext.
 *
 * Handlers:
 * 1. Phantom Limb — detect missing co-loaded rules
 * 2. Instruction Gravity — predict likely agents from rule fingerprint
 * 3. Rule Conflict Detector — find contradictory directives
 *
 * HTTP analytics hook runs separately (native HTTP in hooks.json, zero code).
 */

import type { HookInput, HookResult } from '../types.js';
import {
  outputSilentSuccess,
  outputPromptContext,
  logHook,
} from '../lib/common.js';
import { existsSync, readFileSync } from 'node:fs';
import { basename } from 'node:path';

const HOOK_NAME = 'instructions-loaded-dispatcher';

// =============================================================================
// Types
// =============================================================================

interface LoadedFile {
  path: string;
  source?: string;
  byte_size?: number;
}

// =============================================================================
// Handler 1: Phantom Limb — Missing Rule Detector
// =============================================================================

/**
 * Co-occurrence pairs: rules that almost always load together.
 * If one loads without the other, warn. Built from observed patterns.
 */
const CO_OCCURRENCE_PAIRS: Array<[string, string, number]> = [
  // [ruleA, ruleB, expected co-occurrence %]
  ['security-sensitive.md', 'ci-workflows.md', 90],
  ['hooks-development.md', 'hot-path-hooks.md', 85],
  ['skill-authoring.md', 'eval-golden.md', 80],
  ['agent-authoring.md', 'skill-authoring.md', 75],
  ['build-required.md', 'count-sync.md', 90],
  ['test-conventions.md', 'eval-golden.md', 70],
  ['scripts-conventions.md', 'build-required.md', 80],
];

function phantomLimb(loadedNames: Set<string>): string | null {
  const missing: string[] = [];

  for (const [ruleA, ruleB, pct] of CO_OCCURRENCE_PAIRS) {
    if (loadedNames.has(ruleA) && !loadedNames.has(ruleB)) {
      missing.push(`${ruleA} loaded without ${ruleB} (${pct}% co-occurrence)`);
    }
    if (loadedNames.has(ruleB) && !loadedNames.has(ruleA)) {
      missing.push(`${ruleB} loaded without ${ruleA} (${pct}% co-occurrence)`);
    }
  }

  if (missing.length === 0) return null;

  logHook(HOOK_NAME, `Phantom Limb: ${missing.length} missing co-loaded rules detected`);
  return `[Phantom Limb] Possibly missing rules:\n${missing.map(m => `  - ${m}`).join('\n')}`;
}

// =============================================================================
// Handler 2: Instruction Gravity — Agent Pre-selector
// =============================================================================

/**
 * Maps rule-set fingerprints to likely agent profiles.
 * Key: rule filename (without .md). Value: agents likely needed.
 */
const RULE_AGENT_MAP: Record<string, string[]> = {
  'security-sensitive': ['security-auditor', 'security-layer-auditor'],
  'hooks-development': ['test-generator', 'code-quality-reviewer'],
  'hot-path-hooks': ['test-generator'],
  'agent-authoring': ['test-generator', 'code-quality-reviewer'],
  'skill-authoring': ['test-generator'],
  'ci-workflows': ['ci-cd-engineer'],
  'scripts-conventions': ['test-generator'],
  'build-required': ['code-quality-reviewer'],
};

function instructionGravity(loadedNames: Set<string>): string | null {
  const agentScores = new Map<string, number>();

  for (const name of loadedNames) {
    const key = name.replace(/\.md$/, '');
    const agents = RULE_AGENT_MAP[key];
    if (agents) {
      for (const agent of agents) {
        agentScores.set(agent, (agentScores.get(agent) || 0) + 1);
      }
    }
  }

  if (agentScores.size === 0) return null;

  // Sort by score descending, take top 3
  const ranked = [...agentScores.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3)
    .map(([agent]) => agent);

  logHook(HOOK_NAME, `Instruction Gravity: predicted agents: ${ranked.join(', ')}`);
  return `[Instruction Gravity] Based on loaded rules, likely agents: ${ranked.join(', ')}`;
}

// =============================================================================
// Handler 3: Rule Conflict Detector
// =============================================================================

interface ConflictSignature {
  patternA: RegExp;
  patternB: RegExp;
  description: string;
}

const CONFLICT_SIGNATURES: ConflictSignature[] = [
  {
    patternA: /never use `Date/i,
    patternB: /use ISO timestamp/i,
    description: 'Date usage: one rule forbids Date, another may require ISO timestamps',
  },
  {
    patternA: /cursor.based pagination/i,
    patternB: /offset pagination/i,
    description: 'Pagination conflict: cursor-based vs offset-based',
  },
  {
    patternA: /commit.*end of session/i,
    patternB: /commit after each logical unit/i,
    description: 'Commit timing: batch-at-end vs incremental (CLAUDE.md wins)',
  },
  {
    patternA: /never auto-commit/i,
    patternB: /auto.*commit/i,
    description: 'Auto-commit policy conflict',
  },
];

function ruleConflictDetector(loadedFiles: LoadedFile[]): string | null {
  // Only check .claude/rules/ files (not CLAUDE.md or plugin instructions)
  const ruleFiles = loadedFiles.filter(f =>
    f.path.includes('.claude/rules/') || f.path.includes('claude/rules/')
  );

  if (ruleFiles.length < 2) return null;

  // Read content of rule files
  const fileContents: Array<{ name: string; text: string }> = [];
  for (const f of ruleFiles) {
    try {
      if (existsSync(f.path)) {
        fileContents.push({
          name: basename(f.path),
          text: readFileSync(f.path, 'utf8'),
        });
      }
    } catch {
      // Skip unreadable files
    }
  }

  const conflicts: string[] = [];
  for (const sig of CONFLICT_SIGNATURES) {
    const matchA = fileContents.find(c => sig.patternA.test(c.text));
    const matchB = fileContents.find(c => sig.patternB.test(c.text));
    if (matchA && matchB && matchA.name !== matchB.name) {
      conflicts.push(`${matchA.name} vs ${matchB.name}: ${sig.description}`);
    }
  }

  if (conflicts.length === 0) return null;

  logHook(HOOK_NAME, `Rule Conflict Detector: ${conflicts.length} conflicts found`);
  return `[Rule Conflicts]\n${conflicts.map(c => `  - ${c}`).join('\n')}\n  CLAUDE.md takes precedence over .claude/rules/*.md`;
}

// =============================================================================
// Main Dispatcher
// =============================================================================

export function instructionsLoadedDispatcher(input: HookInput): HookResult {
  const filesLoaded: LoadedFile[] = (input as unknown as Record<string, unknown>).files_loaded as LoadedFile[] ?? [];

  if (filesLoaded.length === 0) {
    logHook(HOOK_NAME, 'No files_loaded in input, skipping');
    return outputSilentSuccess();
  }

  logHook(HOOK_NAME, `Processing ${filesLoaded.length} loaded instruction files`);

  // Extract rule filenames for fingerprinting
  const loadedNames = new Set(filesLoaded.map(f => basename(f.path)));

  const contextParts: string[] = [];

  // Handler 1: Phantom Limb
  try {
    const phantom = phantomLimb(loadedNames);
    if (phantom) contextParts.push(phantom);
  } catch (err) {
    logHook(HOOK_NAME, `Phantom Limb failed: ${err}`, 'warn');
  }

  // Handler 2: Instruction Gravity
  try {
    const gravity = instructionGravity(loadedNames);
    if (gravity) contextParts.push(gravity);
  } catch (err) {
    logHook(HOOK_NAME, `Instruction Gravity failed: ${err}`, 'warn');
  }

  // Handler 3: Rule Conflict Detector
  try {
    const conflicts = ruleConflictDetector(filesLoaded);
    if (conflicts) contextParts.push(conflicts);
  } catch (err) {
    logHook(HOOK_NAME, `Rule Conflict Detector failed: ${err}`, 'warn');
  }

  if (contextParts.length === 0) {
    logHook(HOOK_NAME, 'All handlers silent');
    return outputSilentSuccess();
  }

  const consolidated = contextParts.join('\n\n');
  logHook(HOOK_NAME, `Consolidated ${contextParts.length} handler outputs`);

  return outputPromptContext(consolidated);
}
